/// <reference types="astro/client" />
/// <reference path="../worker-configuration.d.ts" />

// `Env` (Worker bindings: ASSETS, SESSION, + anything added to wrangler.jsonc)
// and the `cloudflare:workers` module are typed by worker-configuration.d.ts,
// generated by `wrangler types` (npm run cf-typegen / postinstall). Don't
// hand-roll them — add bindings to wrangler.jsonc and regenerate.

// Astro 7 + CF adapter v14: `Astro.locals` exposes `cfContext` (ExecutionContext,
// for waitUntil). The legacy `locals.runtime.env` was removed — read env via
// `import { env } from 'cloudflare:workers'` instead.
type CloudflareRuntime = import('@astrojs/cloudflare').Runtime;

declare namespace App {
  interface Locals extends CloudflareRuntime {}
}

// Public, build-time-inlined env vars (PUBLIC_ prefix only).
interface ImportMetaEnv {
  readonly PUBLIC_SANITY_PROJECT_ID: string;
  readonly PUBLIC_SANITY_DATASET: string;
  readonly PUBLIC_SANITY_API_VERSION: string;
  readonly PUBLIC_GA_MEASUREMENT_ID: string;
  readonly PUBLIC_TURNSTILE_SITE_KEY: string;
}

interface ImportMeta {
  readonly env: ImportMetaEnv;
}

// Cloudflare Turnstile global (loaded via the api.js script tag), shared by the
// ContactForm (visible) and CommandPalette (invisible) islands.
interface TurnstileApi {
  render(
    el: HTMLElement | string,
    opts: {
      sitekey: string;
      theme?: 'auto' | 'light' | 'dark';
      size?: 'normal' | 'compact' | 'flexible' | 'invisible';
      appearance?: 'always' | 'execute' | 'interaction-only';
      callback?: (token: string) => void;
      'expired-callback'?: () => void;
      'error-callback'?: () => void;
    },
  ): string;
  reset(id?: string): void;
  remove(id?: string): void;
  execute(el?: HTMLElement | string, opts?: { callback?: (token: string) => void }): void;
  getResponse(id?: string): string | undefined;
}

interface Window {
  turnstile?: TurnstileApi;
}
